class Solution:
    def findMinDifference(self, timeList: List[str]) -> int:
        mins = []
        for t in timeList:
            h, m = map(int, t.split(":"))
            mins.append(h * 60 + m)
        mins.sort()
        ans = 24 * 60
        for i in range(1, len(mins)):
            ans = min(ans, mins[i] - mins[i-1])
        ans = min(ans, 24*60 - mins[-1] + mins[0])
        return ans

