class Solution {
public:
    int findMinDifference(vector<string>& timeList) {
        vector<int> m;
        for (auto& t : timeList) {
            int h = stoi(t.substr(0,2)), mi = stoi(t.substr(3,2));
            m.push_back(h*60+mi);
        }
        sort(m.begin(), m.end());
        int ans = 1440;
        for (int i = 1; i < (int)m.size(); i++) ans = min(ans, m[i]-m[i-1]);
        ans = min(ans, 1440 - m.back() + m.front());
        return ans;
    }
};
